        const exactUsers = allUsers.filter(u =>
            u.name.toLowerCase() === ql ||
            u.handle.toLowerCase() === ql ||
            u.handle.toLowerCase() === "@" + ql
        );
        const closeUsers = exactUsers.length === 0
            ? allUsers.filter(u => u.name.toLowerCase().includes(ql) || u.handle.toLowerCase().includes(ql))
            : [];
        const matchedUsers = exactUsers.length === 1 ? exactUsers : closeUsers.length === 1 ? closeUsers : [];
        const exactProducts = Object.values(PRODUCT_DETAILS).filter(p => p.name.toLowerCase() === ql);
        const closeProducts = exactProducts.length === 0
