        // Close match: place name includes query OR query includes place name (handles searches like
        // "Be Our Guest Restaurant" that are longer than the canonical name "Be Our Guest").
        const closePlaces = exactPlaces.length === 0
            ? PLACES_GRID.filter(p => p.name.toLowerCase().includes(ql) || ql.includes(p.name.toLowerCase()))
            : [];
        const matchedPlaces = exactPlaces.length === 1 ? exactPlaces : closePlaces.length === 1 ? closePlaces : [];
        const matchedPosts = FEED.filter(p => (p.caption || "").toLowerCase().includes(ql) || (p.place || "").toLowerCase().includes(ql));
