    // Drives the animated walking puck along the route during active navigation.
    // Advances progress 0 → 1 over ~60 seconds of walking time (prototype pacing). Loops back on complete so demos keep running.
    useEffect(() => {
        if (!navActive) { setNavProgress(0); return; }
        const id = setInterval(() => {
            setNavProgress(p => {
                const next = p + 0.004; // ~4% every 250ms → ~60s full route
                return next >= 1 ? 0 : next;
            });
        }, 250);
        return () => clearInterval(id);
    }, [navActive]);
    // === BANNER: the signature element -- dark strip below image with place/user info ===
