                                                                <span style={{ fontSize: 12, fontWeight: 600, color: "rgba(255,255,255,0.78)", fontFamily: F, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", textShadow: hasMedia ? "0 1px 3px rgba(0,0,0,0.55)" : "none" }}>{bc.venue}</span>
