                                            {pin.icon === "hotel" && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={iconColor} strokeWidth="2"><path d="M3 21V7a2 2 0 0 1 2-2h6v16" /><path d="M13 21V3h6a2 2 0 0 1 2 2v16" /><path d="M7 10h0M17 10h0M7 14h0M17 14h0" /></svg>}
