                                                <button style={{ all: "unset", cursor: "pointer", width: "100%", padding: "12px 0", borderRadius: 100, border: "1.5px solid " + A.brand, display: "flex", alignItems: "center", justifyContent: "center", boxSizing: "border-box" }}>
                                                    <span style={{ fontSize: 14, fontWeight: 600, color: A.brand, fontFamily: F }}>Post a Review</span>
                                                </button>
