                                                <div style={{ width: 22, height: 22, borderRadius: "50%", background: "#FFF", position: "absolute", top: 3, left: allOn ? 21 : 3, transition: "left 0.2s ease", boxShadow: "0 1px 3px rgba(0,0,0,0.15)" }} />
