                    "lg2": ["Buzz Lightyear", "The Barnstormer", "Dumbo", "it's a small world", "Pirates", "Winnie the Pooh", "Speedway", "Jungle Cruise"],
                    "lg3": ["Refillable Mugs", "Pack Snacks", "Free Water Cups", "Mobile Order Early", "Resort Hopping", "Gas Stations Nearby", "Split Meals", "Memory Maker Tips", "Off-Season Dates", "Outlet Malls", "AP Discounts", "Free Parking Hack", "Grocery Delivery", "Budget Souvenirs", "Free Entertainment"],
                    "lg4": ["Club Cool", "Kidcot Fun Stops", "Japan Garden", "Les Halles", "Morocco Pavilion", "Takumi-Tei", "Sea Base"],
                    "pl1-1": ["Grey Stuff", "Dole Whip Float", "Turkey Leg", "Tomorrowland Burger", "Cheshire Cat Tail", "Spring Rolls", "Citrus Swirl", "Loaded Tots", "Plaza Ice Cream", "Corn Dog Nuggets"],
