                                                        <div style={{ aspectRatio: "1/1", position: "relative", overflow: "hidden" }}>
                                                            <img src={or.img} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                                                            <div style={{ position: "absolute", bottom: 8, right: 10, padding: "3px 8px", borderRadius: 100, background: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)", fontSize: 11, fontWeight: 600, color: "#FFF" }}>{or.price}</div>

                                                        </div>
