                                            <img src={prdImgs[prdIdx]?.replace("w=400", "w=1200").replace("w=800", "w=1200").replace("q=80", "q=95")} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block", transition: "opacity 0.2s" }} />
