                                            const downRaters = (qr.down || []).map(id => ({ user: getUser(id), vote: "down" }));
                                            const reviewRaters = reviewPosts.map(r => ({ user: getUser(r.userId), vote: r.vote }));
                                            const allRaters = [...reviewRaters, ...upRaters, ...downRaters].filter(r => r.user);
                                            const seen = new Set();
                                            const uniqueRaters = allRaters.filter(r => { if (seen.has(r.user.id)) return false; seen.add(r.user.id); return true; });
                                            const networkRaters = uniqueRaters.filter(r => networkIds.has(r.user.id));
                                            const otherRaters = uniqueRaters.filter(r => !networkIds.has(r.user.id));
                                            if (networkRaters.length === 0 && otherRaters.length === 0) return null;
