                                                    {answer.onScene && <span style={{ display: "inline-flex", alignItems: "center", gap: 4, fontSize: 10, fontWeight: 800, color: "#0F8A3F", background: "rgba(15,138,63,0.10)", padding: "2px 8px 2px 7px", borderRadius: 100, fontFamily: F, letterSpacing: 0.4, textTransform: "uppercase" }}><span style={{ width: 6, height: 6, borderRadius: "50%", background: "#0F8A3F", boxShadow: "0 0 6px rgba(15,138,63,0.7)", animation: "pulse 1.6s ease-in-out infinite" }} />On Scene</span>}
