                                                        <button onClick={(e) => { e.stopPropagation(); setCommentMenuId(commentMenuId === answerKey ? null : answerKey); }} style={{ all: "unset", cursor: "pointer", display: "flex", alignItems: "center", padding: 2 }} aria-label="More">
                                                            <svg width="16" height="16" viewBox="0 0 24 24" fill={A.foggy}><circle cx="5" cy="12" r="1.8" /><circle cx="12" cy="12" r="1.8" /><circle cx="19" cy="12" r="1.8" /></svg>
                                                        </button>
