                                                                        <button onClick={(e) => { e.stopPropagation(); setCommentMenuId(null); setToastMsg("Answer reported"); setTimeout(() => setToastMsg(null), 1500); }} style={{ all: "unset", cursor: "pointer", display: "flex", alignItems: "center", gap: 8, width: "100%", boxSizing: "border-box", padding: "11px 14px" }}>
                                                                            <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={A.dark} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z" /><line x1="4" y1="22" x2="4" y2="15" /></svg>
                                                                            <span style={{ fontSize: 14, fontWeight: 600, color: A.dark, fontFamily: F }}>Report</span>
                                                                        </button>
