                                            {(notif.type === "comment" || notif.type === "mention") && <svg width="10" height="10" viewBox="0 0 24 24" fill="#FFF" stroke="none"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" /></svg>}
