                                                            <span style={{ fontSize: 12, fontWeight: 500, color: A.foggy, fontFamily: F, display: "block", lineHeight: 1.3, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{item.subtitle} · <span style={{ color: kindBgColor[item.kind], fontWeight: 600 }}>{kindLabel[item.kind]}</span></span>
