                                                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={A.foggy} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><polygon points="3 11 22 2 13 21 11 13 3 11" /></svg>
