                                <button onClick={() => { setNewEventTitle(""); setNewEventLocation(""); setNewEventType("dining"); setNewEventDate(selected); setNewEventHour(10); setNewEventMinute(0); setNewEventAmPm("AM"); setNewEventReminder("15"); setNewEventReminder2("none"); setNewEventAttendees([]); setShowAttendeePicker(false); setAttendeeSearch(""); setNewEventAllDay(false); setNewEventEndDate(selected); setNewEventEndHour(11); setNewEventEndMinute(0); setNewEventEndAmPm("AM"); setShowEventEndDatePicker(false); setShowEventEndTimePicker(false); setNewEventRepeat("never"); setNewEventTravelTime("none"); setNewEventNotes(""); setNewEventUrl(""); setShowRepeatPicker(false); setShowTravelPicker(false); setShowReminderPicker(null); const sd = new Date(selected); setAddEventCalMonth({ y: sd.getFullYear(), m: sd.getMonth() }); setShowAddEventSheet(true); }} style={{ all: "unset", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", width: 44, height: 44, borderRadius: "50%", background: A.bg, boxShadow: "0 4px 16px rgba(0,0,0,0.12)", flexShrink: 0 }} aria-label="Add event">
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={A.dark} strokeWidth="2.5" strokeLinecap="round"><line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" /></svg>
                                </button>
