                const repeatLabels = { never: "Never", daily: "Daily", weekly: "Weekly", monthly: "Monthly", yearly: "Yearly" };
                const travelLabels = { none: "None", "15": "15 min", "30": "30 min", "60": "1 hr" };
                const formatDateShort = (ds) => { if (!ds) return ""; const d = new Date(ds); return d.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" }); };
                const attendees = (ev.attendees || []).map(uid => getUser(uid)).filter(Boolean);
