                                        const reminderLabels = { none: "None", "0": "At time of event", "5": "5 min before", "15": "15 min before", "30": "30 min before", "60": "1 hr before", "120": "2 hr before", "1440": "1 day before", "2880": "2 days before", "10080": "1 week before" };
                                        const reminderOpts = [{ key: "none", label: "None" }, { key: "0", label: "At event" }, { key: "5", label: "5 min" }, { key: "15", label: "15 min" }, { key: "30", label: "30 min" }, { key: "60", label: "1 hr" }, { key: "120", label: "2 hr" }, { key: "1440", label: "1 day" }, { key: "2880", label: "2 days" }, { key: "10080", label: "1 week" }];
