                                            {askTopicSearch && <button onClick={() => setAskTopicSearch("")} style={{ all: "unset", cursor: "pointer", display: "flex" }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={A.foggy} strokeWidth="2"><path d="M18 6L6 18M6 6l12 12" /></svg></button>}
