                                                if (type === "Broadcast") { setBroadcastStep("compose"); setAiClassifyStatus(null); setBroadcastChips([]); setBroadcastAddingChip(false); setBroadcastVoiceState(null); setBroadcastCat(null); setBroadcastSub(null); setBroadcastVenue(null); setBroadcastVenueSearch(""); setShowVenueSlideUp(false); setSelectedWaitTime(null); setBroadcastNote(""); setHotTakeVote(null); setBroadcastAttachment(null); setNewPostType("Broadcast"); return; }
                                                if (newPostType !== type) { setAttachedPlaces([]); setAttachedRating(null); setTaggedPeople([]); setAttachedLists([]); setReviewSubject(null); setReviewVote(null); setPhotoCaption(""); setPostLink(""); setPostCarouselIdx(0); setActivePicker(null); setPickerSearch(""); setPhotoOverrides({}); setShowPhotoEditPage(false); setPerPhotoActivePicker(null); setPerPhotoPickerSearch(""); if (type === "Post") { setPostStep("grid"); setSelectedPostPhotos([]); } }
                                                setNewPostType(type);
