                                                    const isPast = dObj < new Date(new Date().toDateString());
                                                    const isCheckIn = bookingCheckIn === dStr;
                                                    const isCheckOut = bookingCheckOut === dStr;
                                                    const inRange = bookingCheckIn && bookingCheckOut && dObj > new Date(bookingCheckIn) && dObj < new Date(bookingCheckOut);
                                                    const disabled = isPast || (bookingDateField === "out" && bookingCheckIn && dObj <= new Date(bookingCheckIn));
