                                                <svg width="140" height="140" viewBox="0 0 140 140" style={{ position: "absolute", inset: 0, transform: "rotate(-90deg)" }}>
                                                    <circle cx="70" cy="70" r="52" fill="none" stroke={A.border} strokeWidth="4" />
                                                    <circle cx="70" cy="70" r="52" fill="none" stroke={A.brand} strokeWidth="4" strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={circumference * (1 - progress)} style={{ transition: "stroke-dashoffset 1s linear" }} />
                                                </svg>
